interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const PROCESSING_FEE_G = 5;
const FIRST_INSURANCE_SURCHARGE_DIVISOR = 10; // 10% surcharge = divide by 10
const TENTHS_PER_G = 10;

const quotePremium = (items: Item[]): number => {
  const itemBaseTenths = items.reduce(
    (sum, item) => sum + BASE_PREMIUMS[item.type] * TENTHS_PER_G,
    0,
  );
  const withFirstInsuranceTenths =
    itemBaseTenths + itemBaseTenths / FIRST_INSURANCE_SURCHARGE_DIVISOR;
  const totalTenths = withFirstInsuranceTenths + PROCESSING_FEE_G * TENTHS_PER_G;
  return Math.ceil(totalTenths / TENTHS_PER_G);
};

export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

