interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const PROCESSING_FEE_G = 5;
const FIRST_INSURANCE_SURCHARGE_DIVISOR = 10; // 10% surcharge expressed as a divisor (avoids 0.1 float drift)
const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE_G = 60;
const RUNE_UNIT_PRICE_G = 25;

const quotePremium = (items: Item[]): number => {
  const runeCount = items.filter((i) => i.type === "rune").length;
  const nonRuneBase = items
    .filter((i) => i.type !== "rune")
    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const runeBase =
    runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_PRICE_G : runeCount * RUNE_UNIT_PRICE_G;
  const policyBase = nonRuneBase + runeBase;
  const withFirstInsuranceSurcharge = policyBase + policyBase / FIRST_INSURANCE_SURCHARGE_DIVISOR;
  return Math.ceil(withFirstInsuranceSurcharge + PROCESSING_FEE_G);
};

export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

