28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PRICE_G = 60;
30	const CURSE_SURCHARGE_RATE = 0.5; // 50% of cursed item's base premium
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3; // 30% of enchanted item's base premium
32	const HIGH_ENCHANTMENT_THRESHOLD = 5;
33	
34	const COMPONENT_TYPES = ["rune", "moonstone"];
35	
36	const priceForComponentGroup = (count: number, unitPrice: number): number =>
37	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE_G : count * unitPrice;
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
40	
41	const isCursed = (item: Item): boolean => item.cursed === true;
42	const isHighlyEnchanted = (item: Item): boolean =>
43	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
44	
45	const surchargeFor = (items: Item[], predicate: (i: Item) => boolean, rate: number): number =>
46	  items.filter(predicate).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
47	
48	const quotePremium = (items: Item[]): number => {
49	  const componentBase = COMPONENT_TYPES.reduce((sum, type) => {
50	    const count = items.filter((i) => i.type === type).length;
51	    return sum + priceForComponentGroup(count, BASE_PREMIUMS[type]);
52	  }, 0);
53	  const otherItemsBase = items
54	    .filter((i) => !isComponent(i))
55	    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
56	  const policyBase = otherItemsBase + componentBase;
57	  const curseSurcharge = surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
58	  const enchantmentSurcharge = surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
59	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
