  });

  describe("quote: integration examples", () => {
    it.todo("newcomer with cursed sword (steel, enchantment 3), 0 years → premium 165 G");
    it.todo("long-standing customer's second contract: cursed sword (steel, enchantment 7), 3 years → premium 160 G");
  });

  describe("quote: errors", () => {
    it.todo("unknown item type causes an error (CLI exits non-zero)");
  });

  describe("claim: insurance sum and cap", () => {
    it.todo("policy with sword: insurance sum 1000, cap 2000");
    it.todo("policy with sword + amulet: insurance sum 1600, cap 3200");
    it.todo("policy with sword + 3 runes: insurance sum 1750 (block does not affect insurance sum)");
    it.todo("cursed sword: cap based on unmodified insurance value (2000, not derived from modified premium)");
    it.todo("policy with two swords: insurance sum 2000, cap 4000");
  });

  describe("claim: standard reimbursement", () => {
    it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400");
    it.todo("rune (no enchantment, no material), damage 200 → payout 100");
  });

  describe("claim: deductible per damage event", () => {
    it.todo("dragon attack damages sword 500 and amulet 300 → payout 600 (deductible per item)");
  });

  describe("claim: special reimbursement clauses", () => {
    it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
    it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full reimbursement, then deductible)");
    it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50%, then deductible)");
    it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (high-enchantment, then deductible)");
  });

  describe("claim: cap exhaustion across successive claims", () => {
    it.todo("sword (cap 2000); first claim 1500 → payout 1400, cap remaining 600");
    it.todo("sword (cap 2000); after first claim cap=600, second claim 1500 → payout 600, cap remaining 0");
  });

  describe("claim: rounding", () => {
    it.todo("payout 350.5 rounds down to 350 (MHPCO's favor)");
  });

  describe("claim: errors", () => {
    it.todo("damage references item type not in policy → error");
    it.todo("damage with negative amount → error");
    it.todo("more damage entries of a type than policy covers → error");
  });

  describe("multi-step scenarios", () => {
    it.todo("claim step references earlier quote step by zero-based policy index");
  });
});

