const INSURANCE_VALUES: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};
const DEDUCTIBLE_G = 100;
const CAP_MULTIPLIER = 2;

interface PolicyState {
  items: Item[];
  remainingCap: number;
}

const insuranceSumFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);

export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
  const policies: Record<number, PolicyState> = {};
  let quoteCount = 0;
  const results: StepResult[] = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const premium = quotePremium(step.items, scenario.customer, quoteCount > 0);
      quoteCount += 1;
      policies[index] = {
        items: step.items,
        remainingCap: CAP_MULTIPLIER * insuranceSumFor(step.items),
      };
      return { premium };
    }
    const policy = policies[step.policy];
    const totalDamage = step.incident.damages.reduce((sum, d) => sum + d.amount, 0);
    const rawPayout = totalDamage - DEDUCTIBLE_G;
    const payout = Math.min(rawPayout, policy.remainingCap);
    policy.remainingCap -= payout;
    return { payout, remainingCap: policy.remainingCap };
  });
  return { results };
};

