192	  const payout = Math.floor(Math.min(rawPayout, policy.remainingCap));
193	  policy.remainingCap -= payout;
194	  return { payout, remainingCap: policy.remainingCap };
195	};
196	
197	const assertKnownItemTypes = (items: Item[]): void => {
198	  const unknown = items.find((item) => !(item.type in BASE_PREMIUMS));
199	  if (unknown) {
200	    throw new Error(`Unknown item type: ${unknown.type}`);
201	  }
202	};
203	
204	export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
205	  const policies: Record<number, PolicyState> = {};
206	
207	  const handleQuote = (step: QuoteStep, index: number): QuoteResult => {
208	    assertKnownItemTypes(step.items);
209	    const isFollowUpContract = Object.keys(policies).length > 0;
210	    const premium = quotePremium(step.items, scenario.customer, isFollowUpContract);
211	    policies[index] = openPolicy(step.items);
212	    return { premium };
213	  };
214	
215	  const handleStep = (step: Step, index: number): StepResult =>
216	    step.op === "quote" ? handleQuote(step, index) : settleClaim(policies[step.policy], step.incident);
217	
218	  return { results: scenario.steps.map(handleStep) };
219	};

